6	//! LLVM dialect for cuda-oxide.
7	//!
8	//! The dialect *modeling* (types, ops, attributes, op-interfaces) now lives
9	//! upstream in [`pliron_llvm`]; this crate is a thin shim that re-exports it so
10	//! existing `llvm_export::{ops,types,attributes,op_interfaces}` paths keep
11	//! resolving, plus the small set of GPU-specific extensions pliron-llvm does
12	//! not carry (named address spaces, syncscope enum, fp16 bit helpers). The
13	//! pure-Rust textual `.ll` exporter ([`export`]) stays here: pliron-llvm only
14	//! emits real `.ll` via an `llvm-sys` bridge, which is exactly what cuda-oxide
15	//! is avoiding.
16	//!
17	//! Registration is automatic: every dialect/op/type/attribute linked into the
18	//! binary registers itself when a [`pliron::context::Context`] is created
19	//! (`Context::default` runs all link-time `CONTEXT_REGISTRATIONS`), so no
20	//! explicit `register()` entry point is needed.
21	
22	pub mod export;
23	
24	/// LLVM types: re-exported from pliron-llvm, plus GPU address-space helpers.
25	pub mod types {
26	    pub use pliron_llvm::types::*;
27	
28	    /// `f16` maps to pliron core's builtin `FP16Type`.
29	    pub use pliron::builtin::types::FP16Type as HalfType;
30	
31	    /// NVVM address spaces (generic=0, global=1, shared=3, constant=4,
32	    /// local=5, tmem=6). pliron-llvm's `PointerType` stores a raw `u32`
33	    /// address space with no named constants, so we keep these here.
34	    pub mod address_space {
35	        /// Generic / flat address space.
36	        pub const GENERIC: u32 = 0;
37	        /// Global memory.
38	        pub const GLOBAL: u32 = 1;
39	        /// Shared (CTA) memory.
40	        pub const SHARED: u32 = 3;
41	        /// Constant memory.
42	        pub const CONSTANT: u32 = 4;
43	        /// Thread-local memory.
44	        pub const LOCAL: u32 = 5;
45	        /// Tensor memory (Blackwell tcgen05).
46	        pub const TMEM: u32 = 6;
47	    }
48	
49	    use pliron::{context::Context, r#type::TypedHandle};
50	    pub use pliron_llvm::types::PointerType;
51	
52	    /// Address-space convenience constructors/predicates re-homed from the
53	    /// pre-migration local `PointerType`. Upstream ships only
54	    /// `PointerType::get(ctx, address_space)` + `address_space()`.
55	    pub trait PointerTypeExt {
56	        /// Pointer into the generic address space.
57	        fn get_generic(ctx: &mut Context) -> TypedHandle<PointerType>;
58	        /// Pointer into the shared address space.
59	        fn get_shared(ctx: &mut Context) -> TypedHandle<PointerType>;
60	        /// Pointer into the global address space.
61	        fn get_global(ctx: &mut Context) -> TypedHandle<PointerType>;
62	        /// Pointer into tensor memory.
63	        fn get_tmem(ctx: &mut Context) -> TypedHandle<PointerType>;
64	        /// True if this pointer is in the shared address space.
65	        fn is_shared(&self) -> bool;
66	        /// True if this pointer is in tensor memory.
67	        fn is_tmem(&self) -> bool;
68	    }
69	
70	    impl PointerTypeExt for PointerType {
71	        fn get_generic(ctx: &mut Context) -> TypedHandle<PointerType> {
72	            PointerType::get(ctx, address_space::GENERIC)
73	        }
74	        fn get_shared(ctx: &mut Context) -> TypedHandle<PointerType> {
75	            PointerType::get(ctx, address_space::SHARED)
76	        }
77	        fn get_global(ctx: &mut Context) -> TypedHandle<PointerType> {
78	            PointerType::get(ctx, address_space::GLOBAL)
79	        }
80	        fn get_tmem(ctx: &mut Context) -> TypedHandle<PointerType> {
81	            PointerType::get(ctx, address_space::TMEM)
82	        }
83	        fn is_shared(&self) -> bool {
84	            self.address_space() == address_space::SHARED
85	        }
86	        fn is_tmem(&self) -> bool {
87	            self.address_space() == address_space::TMEM
88	        }
89	    }
90	}
