92	/// LLVM attributes: re-exported from pliron-llvm, plus the syncscope enum and
93	/// the cuda-oxide names for atomic ordering / rmw-kind.
94	pub mod attributes {
95	    pub use pliron_llvm::attributes::*;
96	
97	    /// `f16` constants use pliron core's builtin `FPHalfAttr`.
98	    pub use pliron::builtin::attributes::FPHalfAttr;
99	
100	    /// Atomic ordering / rmw-kind were named `Llvm*` locally; upstream calls
101	    /// them `Atomic*Attr`. Keep the local names resolving.
102	    pub use pliron_llvm::attributes::{
103	        AtomicOrderingAttr as LlvmAtomicOrdering, AtomicRmwKindAttr as LlvmAtomicRmwKind,
104	    };
105	
106	    /// Synchronization scope for atomics. pliron-llvm models syncscope as a
107	    /// free-form `Option<String>` (None = system); cuda-oxide only emits these
108	    /// three scopes, so we keep the enum at the lowering boundary and translate
109	    /// to pliron's representation via [`LlvmSyncScope::to_pliron`].
110	    #[derive(Clone, Copy, PartialEq, Eq, Debug)]
111	    pub enum LlvmSyncScope {
112	        /// System-wide scope (`syncscope("")` / default).
113	        System,
114	        /// Device (GPU) scope.
115	        Device,
116	        /// Block / CTA scope.
117	        Block,
118	    }
119	
120	    impl LlvmSyncScope {
121	        /// Map to pliron's free-form syncscope string (`None` = system).
122	        pub fn to_pliron(self) -> Option<String> {
123	            match self {
124	                LlvmSyncScope::System => None,
125	                LlvmSyncScope::Device => Some("device".to_string()),
126	                LlvmSyncScope::Block => Some("block".to_string()),
127	            }
128	        }
129	    }
130	}
