162	    /// Inline asm semantics for LLVM optimization hints.
163	    ///
164	    /// This is the complete classification: two orthogonal axes (convergent ×
165	    /// side-effects) produce exactly four variants, all valid for GPU inline
166	    /// asm. No further axes are needed because:
167	    ///
168	    /// - **Memory effects** (`nomem`/`readonly`/`readwrite`) are unnecessary:
169	    ///   cuda-oxide's inline asm is either a pure register-to-register
170	    ///   conversion or a full side-effecting op. Fine-grained memory
171	    ///   classification would only help if we lowered loads/stores through
172	    ///   inline asm, which we don't — those go through proper LLVM ops.
173	    ///
174	    /// - **`noreturn`/`may_unwind`** don't apply: PTX inline asm always
175	    ///   returns and never unwinds.
176	    ///
177	    /// - **`preserves_flags`/`nostack`** are CPU concepts with no PTX
178	    ///   equivalent.
179	    #[pliron_attr(name = "llvm.asm_kind", format, verifier = "succ")]
180	    #[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
181	    pub enum AsmKind {
182	        /// Convergent + side effects. Warp-synchronous operations that
183	        /// synchronize threads or write memory: `bar.sync`, `mma.sync`,
184	        /// `wgmma`, `tcgen05`, `cp.async`.
185	        Convergent,
186	        /// Convergent, no side effects. Warp-collective operations whose
187	        /// result depends on which threads are active but that produce no
188	        /// observable effects beyond their register output: `shfl.sync`,
189	        /// `vote.sync`, `match.sync`.
190	        ConvergentPure,
191	        /// Side effects, not convergent. Non-collective operations that
192	        /// modify memory or hardware state: `st.global` via asm, hardware
193	        /// timer reads.
194	        SideEffect,
195	        /// No side effects, not convergent. Pure register-to-register data
196	        /// conversions: `cvt.rn.f16x2.f32`, `cvt.rn.bf16x2.f32`, `prmt`.
197	        Pure,
198	    }
199	
200	    /// Op-attribute key for the inline-asm kind tag.
201	    const ASM_KIND_KEY: &str = "cuda_oxide_asm_kind";
202	
203	    /// Builder extension for `InlineAsmOp` that tags the op with an [`AsmKind`].
204	    pub trait InlineAsmOpExt {
205	        /// Build an `InlineAsmOp` tagged with the given [`AsmKind`].
206	        fn build(
207	            ctx: &mut Context,
208	            result_ty: TypeHandle,
209	            inputs: Vec<Value>,
210	            asm_template: &str,
211	            constraints: &str,
212	            kind: AsmKind,
213	        ) -> Self;
214	    }
215	
216	    impl InlineAsmOpExt for InlineAsmOp {
217	        fn build(
218	            ctx: &mut Context,
219	            result_ty: TypeHandle,
220	            inputs: Vec<Value>,
221	            asm_template: &str,
222	            constraints: &str,
223	            kind: AsmKind,
224	        ) -> Self {
225	            let convergent = matches!(kind, AsmKind::Convergent | AsmKind::ConvergentPure);
226	            let op = InlineAsmOp::new(
227	                ctx,
228	                result_ty,
229	                inputs,
230	                asm_template,
231	                constraints,
232	                convergent,
233	            );
234	            let key = Identifier::try_new(ASM_KIND_KEY.to_string()).expect("valid identifier");
235	            op.get_operation().deref_mut(ctx).attributes.set(key, kind);
236	            op
237	        }
238	    }
239	
240	    /// Query the [`AsmKind`] stored on an `InlineAsmOp`, if present.
241	    ///
242	    /// Returns `None` for ops that were not built with [`InlineAsmOpExt::build`]
243	    /// (e.g., user-written `ptx_asm!` ops, which carry separate sideeffect /
244	    /// convergent attributes instead).
245	    pub fn asm_kind_opt(ctx: &Context, op: &InlineAsmOp) -> Option<AsmKind> {
246	        let key = Identifier::try_new(ASM_KIND_KEY.to_string()).expect("valid identifier");
247	        op.get_operation()
248	            .deref(ctx)
249	            .attributes
250	            .get::<AsmKind>(&key)
251	            .copied()
252	    }
253	
254	    /// Query the [`AsmKind`] stored on an `InlineAsmOp`.
255	    ///
256	    /// Returns `AsmKind::SideEffect` if the attribute is missing (safe default:
257	    /// assume side effects).
258	    pub fn asm_kind(ctx: &Context, op: &InlineAsmOp) -> AsmKind {
259	        asm_kind_opt(ctx, op).unwrap_or(AsmKind::SideEffect)
260	    }
