279	    /// Debug type metadata for a local variable described by `llvm.dbg.declare`.
280	    #[derive(Clone, Debug, Eq, Hash, PartialEq)]
281	    pub enum DebugLocalTypeKind {
282	        /// A scalar `DIBasicType`.
283	        Basic {
284	            name: String,
285	            size_bits: u64,
286	            encoding: &'static str,
287	        },
288	        /// A pointer/reference `DIDerivedType`.
289	        Pointer { name: String, size_bits: u64 },
290	        /// A struct or tuple `DICompositeType` (`DW_TAG_structure_type`).
291	        ///
292	        /// Member offsets come from rustc's real layout, not declaration order,
293	        /// so this is correct even for `repr(Rust)` field reordering. Tuples are
294	        /// modelled as a struct whose members are named `__0`, `__1`, ...
295	        Struct {
296	            name: String,
297	            size_bits: u64,
298	            members: Vec<DebugTypeMember>,
299	        },
300	        /// A fixed-length array `DICompositeType` (`DW_TAG_array_type`).
301	        Array {
302	            name: String,
303	            size_bits: u64,
304	            element: Box<DebugLocalTypeKind>,
305	            count: u64,
306	        },
307	    }
308	
309	    /// One member of a [`DebugLocalTypeKind::Struct`].
310	    #[derive(Clone, Debug, Eq, Hash, PartialEq)]
311	    pub struct DebugTypeMember {
312	        pub name: String,
313	        /// Byte-offset of the member within its parent, in bits.
314	        pub offset_bits: u64,
315	        pub ty: DebugLocalTypeKind,
316	    }
317	
318	    impl DebugLocalTypeKind {
319	        /// Size of this type in bits, used to fill `DIDerivedType`/member sizes.
320	        pub fn size_bits(&self) -> u64 {
321	            match self {
322	                DebugLocalTypeKind::Basic { size_bits, .. }
323	                | DebugLocalTypeKind::Pointer { size_bits, .. }
324	                | DebugLocalTypeKind::Struct { size_bits, .. }
325	                | DebugLocalTypeKind::Array { size_bits, .. } => *size_bits,
326	            }
327	        }
328	    }
329	
330	    /// Map a serialized DWARF encoding name back to its `&'static str`.
331	    fn debug_encoding_from_str(s: &str) -> Option<&'static str> {
332	        match s {
333	            "DW_ATE_boolean" => Some("DW_ATE_boolean"),
334	            "DW_ATE_float" => Some("DW_ATE_float"),
335	            "DW_ATE_signed" => Some("DW_ATE_signed"),
336	            "DW_ATE_unsigned" => Some("DW_ATE_unsigned"),
337	            _ => None,
338	        }
339	    }
340	
341	    /// Serialize a type tree into a compact, escape-safe string.
342	    ///
343	    /// Strings are length-prefixed (`<byte-len> <bytes>`) so arbitrary type
344	    /// names (`&[u32]`, `Foo<'_, u64>`) round-trip without delimiter escaping.
345	    /// Numbers are space-terminated. This is the value stored under
346	    /// [`DEBUG_LOCAL_TYPE_KEY`]; the reader is [`deserialize_debug_type`].
347	    fn serialize_debug_type(ty: &DebugLocalTypeKind, out: &mut String) {
348	        fn put_u64(out: &mut String, n: u64) {
349	            out.push_str(&n.to_string());
350	            out.push(' ');
351	        }
352	        fn put_str(out: &mut String, s: &str) {
353	            put_u64(out, s.len() as u64);
354	            out.push_str(s);
355	        }
356	        match ty {
357	            DebugLocalTypeKind::Basic {
358	                name,
359	                size_bits,
360	                encoding,
361	            } => {
362	                out.push('b');
363	                put_u64(out, *size_bits);
364	                put_str(out, encoding);
365	                put_str(out, name);
366	            }
367	            DebugLocalTypeKind::Pointer { name, size_bits } => {
368	                out.push('p');
369	                put_u64(out, *size_bits);
370	                put_str(out, name);
371	            }
372	            DebugLocalTypeKind::Struct {
373	                name,
374	                size_bits,
375	                members,
376	            } => {
377	                out.push('s');
378	                put_u64(out, *size_bits);
379	                put_str(out, name);
380	                put_u64(out, members.len() as u64);
381	                for member in members {
382	                    put_str(out, &member.name);
383	                    put_u64(out, member.offset_bits);
384	                    serialize_debug_type(&member.ty, out);
385	                }
386	            }
387	            DebugLocalTypeKind::Array {
388	                name,
389	                size_bits,
390	                element,
391	                count,
392	            } => {
393	                out.push('a');
394	                put_u64(out, *size_bits);
395	                put_str(out, name);
396	                put_u64(out, *count);
397	                serialize_debug_type(element, out);
398	            }
399	        }
400	    }
401	
402	    /// Reverse of [`serialize_debug_type`]. Returns `None` on malformed input.
403	    fn deserialize_debug_type(bytes: &[u8], pos: &mut usize) -> Option<DebugLocalTypeKind> {
404	        fn take_u64(bytes: &[u8], pos: &mut usize) -> Option<u64> {
405	            let start = *pos;
406	            while *pos < bytes.len() && bytes[*pos] != b' ' {
407	                *pos += 1;
408	            }
409	            let n: u64 = std::str::from_utf8(&bytes[start..*pos])
410	                .ok()?
411	                .parse()
412	                .ok()?;
413	            *pos += 1; // consume the space
414	            Some(n)
415	        }
416	        fn take_str(bytes: &[u8], pos: &mut usize) -> Option<String> {
417	            let len = take_u64(bytes, pos)? as usize;
418	            let end = pos.checked_add(len)?;
419	            if end > bytes.len() {
420	                return None;
421	            }
422	            let s = std::str::from_utf8(&bytes[*pos..end]).ok()?.to_string();
423	            *pos = end;
424	            Some(s)
425	        }
426	
427	        let tag = *bytes.get(*pos)?;
428	        *pos += 1;
429	        match tag {
430	            b'b' => {
431	                let size_bits = take_u64(bytes, pos)?;
432	                let encoding = debug_encoding_from_str(&take_str(bytes, pos)?)?;
433	                let name = take_str(bytes, pos)?;
434	                Some(DebugLocalTypeKind::Basic {
435	                    name,
436	                    size_bits,
437	                    encoding,
438	                })
439	            }
440	            b'p' => {
441	                let size_bits = take_u64(bytes, pos)?;
442	                let name = take_str(bytes, pos)?;
443	                Some(DebugLocalTypeKind::Pointer { name, size_bits })
444	            }
445	            b's' => {
446	                let size_bits = take_u64(bytes, pos)?;
447	                let name = take_str(bytes, pos)?;
448	                let member_count = take_u64(bytes, pos)? as usize;
449	                let mut members = Vec::with_capacity(member_count);
450	                for _ in 0..member_count {
451	                    let member_name = take_str(bytes, pos)?;
452	                    let offset_bits = take_u64(bytes, pos)?;
453	                    let ty = deserialize_debug_type(bytes, pos)?;
454	                    members.push(DebugTypeMember {
455	                        name: member_name,
456	                        offset_bits,
457	                        ty,
458	                    });
459	                }
460	                Some(DebugLocalTypeKind::Struct {
461	                    name,
462	                    size_bits,
463	                    members,
464	                })
465	            }
466	            b'a' => {
467	                let size_bits = take_u64(bytes, pos)?;
468	                let name = take_str(bytes, pos)?;
469	                let count = take_u64(bytes, pos)?;
470	                let element = Box::new(deserialize_debug_type(bytes, pos)?);
471	                Some(DebugLocalTypeKind::Array {
472	                    name,
473	                    size_bits,
474	                    element,
475	                    count,
476	                })
477	            }
478	            _ => None,
479	        }
480	    }
