625	    /// Attach a function's MIR source-scope table.
626	    pub fn set_debug_source_scope_map(
627	        ctx: &mut Context,
628	        op: Ptr<Operation>,
629	        map: &DebugSourceScopeMap,
630	    ) {
631	        // The reader (`debug_source_scope_map`) reconstructs scope ids as
632	        // `0..count`, so the writer's per-scope attr keys must use exactly those
633	        // ids. rustc's `SourceScope` indices are dense `0..len`, which makes this
634	        // hold today. Assert it so a future sparse/reordered producer fails
635	        // loudly here instead of silently mislabeling parent/scope links.
636	        debug_assert!(
637	            map.scopes
638	                .iter()
639	                .enumerate()
640	                .all(|(idx, scope)| scope.id as usize == idx),
641	            "DebugSourceScopeMap scope ids must be dense 0..len to round-trip"
642	        );
643	        set_string_attr(
644	            ctx,
645	            op,
646	            DEBUG_SOURCE_SCOPE_COUNT_KEY,
647	            map.scopes.len().to_string(),
648	        );
649	        set_string_attr(
650	            ctx,
651	            op,
652	            DEBUG_SOURCE_SCOPE_LOCATION_COUNT_KEY,
653	            map.locations.len().to_string(),
654	        );
655	
656	        for scope in &map.scopes {
657	            let id = scope.id;
658	            if let Some(parent) = scope.parent {
659	                set_string_attr(ctx, op, &debug_scope_key(id, "parent"), parent.to_string());
660	            }
661	            if let Some(span) = &scope.span {
662	                set_debug_position_attrs(ctx, op, id, "span", span);
663	            }
664	            if let Some(inlined) = &scope.inlined {
665	                set_string_attr(
666	                    ctx,
667	                    op,
668	                    &debug_scope_key(id, "callee"),
669	                    inlined.callee_name.clone(),
670	                );
671	                if let Some(callsite) = &inlined.callsite {
672	                    set_debug_position_attrs(ctx, op, id, "callsite", callsite);
673	                }
674	            }
675	        }
676	
677	        for (idx, location) in map.locations.iter().enumerate() {
678	            set_string_attr(
679	                ctx,
680	                op,
681	                &debug_scope_location_key(idx, "scope"),
682	                location.scope.to_string(),
683	            );
684	            set_debug_scope_location_position_attrs(ctx, op, idx, &location.pos);
685	        }
686	    }
