688	    /// Read a function's MIR source-scope table.
689	    pub fn debug_source_scope_map(
690	        ctx: &Context,
691	        op: Ptr<Operation>,
692	    ) -> Option<DebugSourceScopeMap> {
693	        let count = get_string_attr(ctx, op, DEBUG_SOURCE_SCOPE_COUNT_KEY)?
694	            .parse()
695	            .ok()?;
696	        let mut scopes = Vec::with_capacity(count);
697	
698	        for id in 0..count as u32 {
699	            let parent = get_string_attr(ctx, op, &debug_scope_key(id, "parent"))
700	                .and_then(|v| v.parse().ok());
701	            let span = debug_position_attrs(ctx, op, id, "span");
702	            let inlined = get_string_attr(ctx, op, &debug_scope_key(id, "callee")).map(|name| {
703	                DebugInlinedScope {
704	                    callee_name: name,
705	                    callsite: debug_position_attrs(ctx, op, id, "callsite"),
706	                }
707	            });
708	            scopes.push(DebugSourceScope {
709	                id,
710	                parent,
711	                span,
712	                inlined,
713	            });
714	        }
715	
716	        let location_count = get_string_attr(ctx, op, DEBUG_SOURCE_SCOPE_LOCATION_COUNT_KEY)
717	            .and_then(|count| count.parse().ok())
718	            .unwrap_or(0);
719	        let mut locations = Vec::with_capacity(location_count);
720	
721	        for idx in 0..location_count {
722	            let scope = get_string_attr(ctx, op, &debug_scope_location_key(idx, "scope"))
723	                .and_then(|v| v.parse().ok())?;
724	            let pos = debug_scope_location_position_attrs(ctx, op, idx)?;
725	            locations.push(DebugSourceScopeLocation { pos, scope });
726	        }
727	
728	        Some(DebugSourceScopeMap { scopes, locations })
729	    }
