2246	fn strip_target_debug_from_ptx(ptx_path: &Path) -> Result<(), PipelineError> {
2247	    let ptx = std::fs::read_to_string(ptx_path).map_err(|e| {
2248	        PipelineError::PtxGeneration(format!(
2249	            "failed to read PTX for line-table debug cleanup ({}): {e}",
2250	            ptx_path.display()
2251	        ))
2252	    })?;
2253	    let stripped = strip_target_debug_from_ptx_text(&ptx);
2254	    if stripped != ptx {
2255	        std::fs::write(ptx_path, stripped).map_err(|e| {
2256	            PipelineError::PtxGeneration(format!(
2257	                "failed to write PTX after line-table debug cleanup ({}): {e}",
2258	                ptx_path.display()
2259	            ))
2260	        })?;
2261	    }
2262	    Ok(())
2263	}
2264	
2265	fn strip_target_debug_from_ptx_text(ptx: &str) -> String {
2266	    let mut out = String::with_capacity(ptx.len());
2267	    for line in ptx.split_inclusive('\n') {
2268	        let (line_body, newline) = line
2269	            .strip_suffix('\n')
2270	            .map_or((line, ""), |without_newline| (without_newline, "\n"));
2271	        out.push_str(&strip_target_debug_from_ptx_line(line_body));
2272	        out.push_str(newline);
2273	    }
2274	    out
2275	}
2276	
2277	fn strip_target_debug_from_ptx_line(line: &str) -> String {
2278	    let indent_len = line.len() - line.trim_start().len();
2279	    let indent = &line[..indent_len];
2280	    let body = &line[indent_len..];
2281	    let Some(rest) = body.strip_prefix(".target") else {
2282	        return line.to_string();
2283	    };
2284	
2285	    let mut parts = rest.split(',');
2286	    let Some(arch) = parts.next() else {
2287	        return line.to_string();
2288	    };
2289	
2290	    let options: Vec<&str> = parts
2291	        .map(str::trim)
2292	        .filter(|option| *option != "debug")
2293	        .collect();
2294	    if !rest
2295	        .split(',')
2296	        .skip(1)
2297	        .any(|option| option.trim() == "debug")
2298	    {
2299	        return line.to_string();
2300	    }
2301	
2302	    let mut stripped = format!("{indent}.target{arch}");
2303	    for option in options {
2304	        stripped.push_str(", ");
2305	        stripped.push_str(option);
2306	    }
2307	    stripped
2308	}
