2310	/// Recursively finds the innermost operation that failed verification.
2311	///
2312	/// Helps produce better error messages by pointing to the specific failing
2313	/// operation rather than just the containing module/function.
2314	fn find_inner_verification_error(
2315	    ctx: &Context,
2316	    op_ptr: Ptr<Operation>,
2317	) -> Option<(Ptr<Operation>, String)> {
2318	    let op = op_ptr.deref(ctx);
2319	
2320	    for region in op.regions() {
2321	        let region_ref = region.deref(ctx);
2322	        for block in region_ref.iter(ctx) {
2323	            let block_ref = block.deref(ctx);
2324	            for child_op in block_ref.iter(ctx) {
2325	                if let Some(err) = find_inner_verification_error(ctx, child_op) {
2326	                    return Some(err);
2327	                }
2328	            }
2329	        }
2330	    }
2331	
2332	    if let Err(e) = op.verify(ctx) {
2333	        // Use .disp(ctx) to get full error with location and backtrace
2334	        return Some((op_ptr, e.disp(ctx).to_string()));
2335	    }
2336	
2337	    None
2338	}
