2340	/// Errors from pipeline execution, categorized by stage.
2341	#[derive(Debug)]
2342	pub enum PipelineError {
2343	    /// Function has no MIR body (shouldn't happen for collected functions).
2344	    NoBody(String),
2345	    /// MIR→Pliron IR translation failed.
2346	    Translation(String),
2347	    /// Pliron IR verification failed (includes failing operation if found).
2348	    Verification {
2349	        name: String,
2350	        message: String,
2351	        operation: Option<String>,
2352	    },
2353	    /// MIR→LLVM lowering failed.
2354	    Lowering(String),
2355	    /// LLVM IR export failed.
2356	    Export(String),
2357	    /// PTX generation via `llc` failed.
2358	    PtxGeneration(String),
2359	}
2360	
2361	impl std::fmt::Display for PipelineError {
2362	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
2363	        match self {
2364	            Self::NoBody(name) => write!(f, "Function '{}' has no MIR body", name),
2365	            Self::Translation(msg) => write!(f, "Translation failed: {}", msg),
2366	            Self::Verification {
2367	                name,
2368	                message,
2369	                operation,
2370	            } => {
2371	                writeln!(f, "Verification failed for '{}':", name)?;
2372	                writeln!(f, "  {}", message)?;
2373	                if let Some(op) = operation {
2374	                    writeln!(f, "  Failed operation:\n{}", op)?;
2375	                }
2376	                Ok(())
2377	            }
2378	            Self::Lowering(msg) => write!(f, "Lowering failed: {}", msg),
2379	            Self::Export(msg) => write!(f, "Export failed: {}", msg),
2380	            Self::PtxGeneration(msg) => write!(f, "PTX generation failed: {}", msg),
2381	        }
2382	    }
2383	}
